// Read inputs — handle both targethost and target_host
const rawHost = (
  $json.target_host || 
  $json.targethost || 
  $json.targetHost || 
  ''
).toString().toLowerCase().trim();

const command = (
  $json.command || 
  $json.cmd || 
  ''
).toString().trim();

const commandType = (
  $json.command_type || 
  $json.commandtype || 
  $json.commandType || 
  'powershell'
).toString().toLowerCase();

// Hostname to IP mapping
const hostMap = {
  'machine1': '192.168.0.20',
  'machine 1': '192.168.0.20',
  'pc1': '192.168.0.20',
  '192.168.0.20': '192.168.0.20',
  'machine2': '192.168.0.252',
  'machine 2': '192.168.0.252',
  'pc2': '192.168.0.252',
  '192.168.0.252': '192.168.0.252'
};

const targetHost = hostMap[rawHost] || rawHost || null;

if (!targetHost) {
  return [{ json: {
    blocked: true,
    reason: `Unknown target host: "${rawHost}". Known hosts: machine1 , machine2 .`,
    command
  }}];
}

if (!command) {
  return [{ json: {
    blocked: true,
    reason: 'No command was provided.',
    command: ''
  }}];
}
// Safety blocklist — exact phrase matching only
const blocklist = [
  'format-volume',
  'format c:',
  'del /s /q',
  'rm -rf',
  'remove-item -recurse -force',
  'fdisk',
  'diskpart',
  'reg delete',
  'rd /s /q',
  'rmdir /s',
  'cipher /w',
  'bcdedit',
  'shutdown /r',
  'shutdown /s',
  'restart-computer'
];


const isDangerous = blocklist.some(b => 
  command.toLowerCase().includes(b.toLowerCase())
);

if (isDangerous) {
  return [{ json: {
    blocked: true,
    reason: 'Command blocked by safety filter — potentially destructive operation detected.',
    command
  }}];
}
// Encode for PowerShell -EncodedCommand
const encoded = Buffer.from(command, 'utf16le').toString('base64');

return [{
  json: {
    target_host: targetHost,
    winrm_url: `http://${targetHost}:5985/wsman`,
    command: command,                          // keep raw for reference
    command_json_safe: JSON.stringify(command), // ← add this
    command_type: commandType,
    encoded_command: encoded,
    blocked: false
  }
}];

return [{
  json: {
    success: false,
    blocked: true,
    message: `🚫 Command blocked: ${$('Prepare & Safety Check').item.json.reason}\n\nBlocked command: ${$('Prepare & Safety Check').item.json.command}`
  }
}];
